/* wms-master-boxmgmt-sql-oracle.xml - selectInfoBoxDlvryDupCount */
SELECT COUNT(1)
  FROM TWORK_INFO_BOX_DLVRY
 WHERE CTKEY = #{ctkey}
   AND BOXBARCODE = #{boxbarcode}
   AND DLVRYCORPCD = #{dlvrycorpcd}

/* wms-master-boxmgmt-sql-oracle.xml - selectBoxDupCount */
SELECT COUNT(1)
  FROM TWORK_MST_BOX
 WHERE CTKEY = #{ctkey}
   AND BOXBARCODE = #{boxbarcode}

mapper.insert:
/* wms-master-boxmgmt-sql-oracle.xml - insertBoxMgmt */
INSERT INTO TWORK_MST_BOX (
	   CTKEY
	 , BOXDIVCD
	 , BOXNM
	 , BOXBARCODE
	 , ICKEY
	 , WIDTH
	 , DEPTH
	 , HEIGHT
	 , CBMSTARTRNG
	 , CBMCLOSRNG
	 , USEYN
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
     )
VALUES (
	   #{ctkey}
	 , #{boxdivcd}
	 , #{boxnm}
	 , #{boxbarcode}
  	 , #{ickey}
	 , COALESCE(#{width}, 0)
	 , COALESCE(#{depth}, 0)
	 , COALESCE(#{height}, 0)
	 , COALESCE(#{cbmstartrng}, 0)
	 , COALESCE(#{cbmclosrng}, 0)
	 , #{useyn}
	 , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , #{surkey}
	 , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , #{surkey}
	 )

mapper.update:
/* wms-master-boxmgmt-sql-oracle.xml - updateBoxMgmt */
UPDATE TWORK_MST_BOX
   SET BOXNM = #{boxnm}
     , ICKEY= #{ickey}
	 , WIDTH = COALESCE(#{width}, 0)
	 , DEPTH = COALESCE(#{depth}, 0)
	 , HEIGHT = COALESCE(#{height}, 0)
	 , CBMSTARTRNG = COALESCE(#{cbmstartrng}, 0)
	 , CBMCLOSRNG = COALESCE(#{cbmclosrng}, 0)
	 , USEYN = #{useyn}
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND BOXDIVCD = #{boxdivcd}
   AND BOXBARCODE = #{boxbarcode}

mapper.delete:
/* wms-master-boxmgmt-sql-oracle.xml - deleteBoxMgmt */
DELETE
  FROM TWORK_MST_BOX
 WHERE CTKEY = #{ctkey}
   AND BOXDIVCD = #{boxdivcd}
   AND BOXBARCODE = #{boxbarcode}

