INSERT INTO TWORK_INFO_BOX_DLVRY (
	   CTKEY
	 , BOXBARCODE
	 , DLVRYCORPCD
	 , BOXTYPECD
	 , DLVRYAMT
	 , INSERTDATE
	 , INSERTURKEY
	 , UPDATEDATE
	 , UPDATEURKEY
)
VALUES (
	   #{ctkey}
     , #{boxbarcode}
     , #{dlvrycorpcd}
     , #{boxtypecd}
     , COALESCE(#{dlvryamt}, 0)
     , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
     , #{surkey}
     , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
     , #{surkey}
     )

