		 , BOXTYPECD = #{boxtypecd}
		 , DLVRYAMT = COALESCE(#{dlvryamt}, 0)
 		 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		 , UPDATEURKEY = #{surkey}
	 WHERE CTKEY = #{ctkey}
	   AND BOXBARCODE = #{boxbarcode}
	   AND DLVRYCORPCD = #{orgDlvrycorpcd}

